import{c as t,Q as o,j as i,m as s}from"./chunks/framework.CdiUUa3G.js";const u=JSON.parse('{"title":"PRD-017 · Sensory Layer — Gyroscope, Sonification & Haptics","description":"","frontmatter":{},"headers":[],"relativePath":"prd/PRD-017.md","filePath":"prd/PRD-017.md"}'),r={name:"prd/PRD-017.md"};function a(n,e,d,l,c,h){return o(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="prd-017-·-sensory-layer-—-gyroscope-sonification-haptics" tabindex="-1">PRD-017 · Sensory Layer — Gyroscope, Sonification &amp; Haptics <a class="header-anchor" href="#prd-017-·-sensory-layer-—-gyroscope-sonification-haptics" aria-label="Permalink to &quot;PRD-017 · Sensory Layer — Gyroscope, Sonification &amp; Haptics&quot;">​</a></h1><blockquote><p>Status · Draft v0.4 (all v1 architectural decisions resolved 2026-05-16) Date · 2026-05-16 Owner · Marko Closes into · RFC-020 Slice gate · v1.x (after PRD-015 mobile + PRD-016 audio narration ship)</p></blockquote><blockquote><p><strong>Why this is a PRD.</strong> Mapping Orrery&#39;s continuous physics streams (orbital velocity, distance, signal delay, regime, fuel, microgravity) onto three additional output channels — gyroscope (input camera control), Web Audio sonification, Vibration / Taptic haptics — turns the device into a physical instrument for understanding orbital mechanics. The decision touches the audio channel (must coexist with PRD-016 narration), the mobile wrapper (uses <code>@capacitor/haptics</code> from PRD-015&#39;s plugin list), the accessibility surface (must respect <code>prefers-reduced-motion</code> + screen readers), and every 3D scene&#39;s camera controller (gyro input pauses when touch is active). It needs a product gate before any sensor permission, audio context, or vibration call lands.</p></blockquote><hr><h2 id="§why" tabindex="-1">§why <a class="header-anchor" href="#§why" aria-label="Permalink to &quot;§why&quot;">​</a></h2><p>The original orrery — the 18th-century brass instrument the product is named after — was a thing you held. You turned the handle. The gears clicked. The metal made sound. The motion was <em>in your hands.</em></p><p>Orrery the web app has rebuilt the visual language of that instrument across 11 routes and 7 3D scenes. What it has not rebuilt is the embodied half: the input you give the instrument with your hand, the sound the instrument makes back, the small physical confirmation that something happened.</p><p>Mobile devices have all three of those affordances already wired in. The gyroscope reads the rotation of the device; tilting becomes camera control. The Web Audio API turns any numerical stream into pitch, gain, filter, reverb. The Vibration API (Android) and Taptic Engine (iOS, via Capacitor) produce tactile pulses. Every frame, Orrery&#39;s physics already computes the streams: heliocentric velocity, distance from Earth, fuel remaining, orbital regime, signal delay. The data exists. The hardware exists. The plumbing between them is the feature.</p><p>This is not ornamental. Sonification has a specific educational advantage over visual display: it conveys <em>change over time</em> more intuitively than numbers. A HUD reading &quot;31.4 km/s&quot; at one instant tells you a number. A tone that rises and falls over the arc of a Mars mission conveys acceleration and deceleration <em>continuously</em>, without requiring the user to watch a specific spot on the screen. The user tilts their phone to look at Mars, hears the velocity tone rising, feels a discrete pulse when the spacecraft crosses Mars&#39;s orbit — three senses confirming the same physical event. That is how humans learn best.</p><p>Kepler knew this. In 1619, he computed the ratios of planetary orbital velocities at perihelion and aphelion and noticed they formed approximate musical intervals. He published them in <em>Harmonices Mundi</em> — the harmony of the worlds. Orrery makes that harmony literal: each planet gets an oscillator tuned to its angular velocity. The solar system has a chord.</p><hr><h2 id="§audiences" tabindex="-1">§audiences <a class="header-anchor" href="#§audiences" aria-label="Permalink to &quot;§audiences&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Audience</th><th>Why the sensory layer helps them</th></tr></thead><tbody><tr><td>Curious learner</td><td>Tilting the phone to orbit is more discoverable than learning two-finger drag-and-pinch. The sound makes the physics audible without reading numbers.</td></tr><tr><td>STEM student</td><td>Discrete tones for orbital regimes, agency-coloured timbres for spacecraft families — sonification is a study aid that doesn&#39;t compete with the visual.</td></tr><tr><td>Educator (classroom / kiosk / museum)</td><td>A device on a table with a kid tilting it and hearing the planets is an entirely different educational artefact than a static screen. The kit becomes the lesson.</td></tr><tr><td>Vision-impaired user</td><td>A planet-selection haptic confirms the touch happened; the sonic identity of <code>/explore</code> (Kepler chord) means the route is identifiable by sound. Captions (PRD-016) supply narration; sensory layer supplies <em>event confirmation.</em></td></tr><tr><td>Power user (any audience)</td><td>Master toggle off by default — opt-in for everyone. Once enabled, the layer disappears into the experience.</td></tr></tbody></table><hr><h2 id="§what-s-already-shipped-sensory-readiness-inventory" tabindex="-1">§what&#39;s already shipped (sensory-readiness inventory) <a class="header-anchor" href="#§what-s-already-shipped-sensory-readiness-inventory" aria-label="Permalink to &quot;§what&#39;s already shipped (sensory-readiness inventory)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Capability</th><th>Status</th><th>Source</th></tr></thead><tbody><tr><td>11 primary nav routes (7 with 3D scenes)</td><td>shipped (v0.6)</td><td>TA.md route inventory</td></tr><tr><td>Camera controllers per 3D scene</td><td>shipped</td><td><code>src/lib/camera-*.ts</code> modules</td></tr><tr><td><code>prefers-reduced-motion</code> respected throughout</td><td>shipped</td><td>ADR-022, ADR-025</td></tr><tr><td>Mobile-first layout (bottom-bar, bottom-sheet patterns)</td><td>shipped (v0.6)</td><td>ADR-018</td></tr><tr><td>Capacitor wrapper with <code>@capacitor/haptics</code> plugin</td><td>planned (PRD-015 / RFC-018, v0.8)</td><td>RFC-018 §6 plugin list</td></tr><tr><td>Audio narration overlay (PRD-016)</td><td>planned (v0.9)</td><td>will share audio channel — see §audio-coexistence below</td></tr><tr><td>Cookie-only persistence (<code>orrery_locale</code>)</td><td>shipped</td><td>ADR-057 — sensory uses <strong>in-memory + sessionStorage only</strong></td></tr></tbody></table><hr><h2 id="§goal" tabindex="-1">§goal <a class="header-anchor" href="#§goal" aria-label="Permalink to &quot;§goal&quot;">​</a></h2><p>Ship a sensory layer that reaches across all 11 routes by v1.x (after PRD-015 mobile + PRD-016 audio land):</p><ul><li><strong>Gyroscope:</strong> mobile-only camera input on the 7 3D-scene routes (<code>/explore</code>, <code>/fly</code> heliocentric, <code>/fly</code> cislunar, <code>/earth</code>, <code>/moon</code>, <code>/mars</code>, <code>/iss</code>, <code>/tiangong</code>).</li><li><strong>Sonification:</strong> desktop + mobile, all <strong>11 routes</strong> (per-route specialisation per RFC-020 §sonification).</li><li><strong>Haptics:</strong> discrete pulse events on Android (web <code>navigator.vibrate</code>) and on both Android + iOS via <code>@capacitor/haptics</code> when running under the Capacitor wrapper.</li></ul><p>The original draft scoped sonification to 6 prototype screens (P01–P06). The v0.6.0 reality is 11 routes and Marko wants editorial parity across all of them.</p><hr><h2 id="§promises-v1" tabindex="-1">§promises (v1) <a class="header-anchor" href="#§promises-v1" aria-label="Permalink to &quot;§promises (v1)&quot;">​</a></h2><ol><li><strong><code>/explore</code> plays a Kepler chord</strong> when AUDIO is on — eight planet oscillators tuned to angular velocity, sine + triangle waveforms, spatial panning that follows camera orientation. The solar system <em>sounds</em> harmonic.</li><li><strong><code>/fly</code> mission arcs are audible.</strong> Velocity → pitch (the protagonist), distance → reverb depth (the isolation), fuel → harmonic distortion (the mortality), signal-delay → echo (the CAPCOM wait). Arrival = major chord.</li><li><strong><code>/fly</code> porkchop topology is heard, not just seen.</strong> Cell-tap plays a tone whose pitch maps to Δv. Drag across the magnifier is continuous sonification of the topology you&#39;re crossing.</li><li><strong><code>/missions</code> has agency tones.</strong> Card selection = agency-coloured chord (NASA warm, ESA bright, JAXA crisp, ROSCOSMOS low, CNSA bright, ISRO mid). Status modulates: ACTIVE = oscillation, FLOWN = clean, PLANNED = soft echo.</li><li><strong><code>/earth</code> orbit regimes are drone-mapped.</strong> LEO = sine, MEO = triangle, GEO = square, HEO = sawtooth, L-points = sine + detune. Selected object boosts its regime drone.</li><li><strong><code>/moon</code> has a continuous filter sweep.</strong> Near-side = warm low-pass, far-side = bright. Landing-site selection plays the agency tone of the operator.</li><li><strong><code>/mars</code> has the same regime + landing-site palette as <code>/earth</code> + <code>/moon</code>,</strong> adapted: distance-from-Earth modulates a global filter (closer = warmer); rover-position selection plays the operator&#39;s agency tone.</li><li><strong><code>/iss</code> modules sing.</strong> Each module gets a tone family by function (habitation = warm low, lab = mid bright, docking = pulsing). Visitor presence (Soyuz / Crew Dragon docked) adds a subtle additional drone. Selected module boosts its tone.</li><li><strong><code>/tiangong</code> uses the same instrument class as <code>/iss</code> but a brighter palette</strong> (triangle + sawtooth instead of sine + triangle). Different agency = different &quot;voice&quot; of the same module-tone instrument.</li><li><strong><code>/science</code> shifts ambient texture per chapter.</strong> life-in-space = warm pad, observation = airy chime texture, mission-phases = rhythmic pulse, basics = a cleaner sustained tone. Discrete chapter switch is a soft transition.</li><li><strong><code>/fleet</code> has spacecraft-family chords.</strong> Selecting a spacecraft = 3-note chord in the agency&#39;s tone palette. ACTIVE status = continuous low ambient drone; FLOWN = clean single tone; PLANNED = soft echoey hint.</li><li><strong><code>/</code> (landing) plays a soft Curator-tour intro tone</strong> when AUDIO is enabled — only at the very top of the page, not on every navigation back.</li><li><strong>Haptic threshold events.</strong> Mission arc crosses Mars orbit → 1 pulse. Δv warning → 1 pulse. Fuel exhaustion → triple pulse. Module / planet / site / spacecraft selection → short single pulse. Solver-complete → triple pulse. 12 patterns total per RFC-020 §haptics.</li><li><strong>Gyroscope camera control</strong> on the 7 3D-scene routes. Reference-frame calibrated (G-C from the original RFC). Touch input pauses gyro (T-B). Recalibrate gesture re-anchors the home position.</li><li><strong>One master toggle (off by default), one settings sheet</strong> in the right of the nav. Long-press on the master toggle opens a sheet with sub-toggles for GYRO / AUDIO / HAPTIC. Desktop hides GYRO + HAPTIC (only AUDIO is meaningful). <code>prefers-reduced-motion</code> users get only AUDIO surfaced.</li></ol><hr><h2 id="§scope" tabindex="-1">§scope <a class="header-anchor" href="#§scope" aria-label="Permalink to &quot;§scope&quot;">​</a></h2><h3 id="v1-in-scope" tabindex="-1">v1 (in scope) <a class="header-anchor" href="#v1-in-scope" aria-label="Permalink to &quot;v1 (in scope)&quot;">​</a></h3><ul><li>All 11 routes get sonification (per-route specialisation; see RFC-020 §sonification details for the 5 new route designs).</li><li>Gyroscope on 7 3D-scene routes (mobile only).</li><li>Haptics on Android (web <code>navigator.vibrate</code>) AND on Android + iOS in Capacitor wrapper (via <code>@capacitor/haptics</code>).</li><li>Master toggle (default OFF) + long-press settings sheet (GYRO / AUDIO / HAPTIC sub-toggles).</li><li>iOS web gyro permission flow (<code>DeviceOrientationEvent.requestPermission()</code> on toggle tap).</li><li><code>prefers-reduced-motion</code> blocks GYRO + HAPTIC; AUDIO remains user-controllable.</li><li>Sonification ducks to ~0.02 gain when PRD-016 narration is playing (the two coexist).</li><li>Settings persist for the session only via in-memory state (per ADR-057). NO localStorage. NO sessionStorage either — runtime-only state. Reload resets to OFF.</li></ul><h3 id="v1-out-of-scope-—-deferred" tabindex="-1">v1 (out of scope — deferred) <a class="header-anchor" href="#v1-out-of-scope-—-deferred" aria-label="Permalink to &quot;v1 (out of scope — deferred)&quot;">​</a></h3><ul><li>Volume slider in settings sheet (ship with tuned defaults; v1.1).</li><li>Headphone detection (auto-enable richer sonification on plug — v1.1).</li><li>Gyro for <code>/fly</code> porkchop magnifier (conflicts with ADR-023; defer).</li><li>Compass / planetarium mode (orient to true north — v1.1).</li><li>MIDI output for performance / education contexts (v2 candidate).</li><li>User-adjustable sensitivity (ship tuned constants; reopen if reviewers complain).</li><li>iOS web haptics (browser limitation; can&#39;t fix). iOS Capacitor haptics covered.</li></ul><hr><h2 id="§must-have-requirements" tabindex="-1">§must-have requirements <a class="header-anchor" href="#§must-have-requirements" aria-label="Permalink to &quot;§must-have requirements&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ID</th><th>Requirement</th></tr></thead><tbody><tr><td><strong>M1</strong></td><td>Master sensory toggle in the nav (small waveform + compass icon, 44×44 px tap target). Default OFF. Single tap toggles all enabled sub-modalities on/off. Long-press opens settings sheet.</td></tr><tr><td><strong>M2</strong></td><td>Settings sheet (bottom-sheet on mobile, dropdown on desktop) with three sub-toggles: GYRO, AUDIO, HAPTIC. All default ON when the master is enabled for the first time. State is in-memory only (lost on reload per ADR-057).</td></tr><tr><td><strong>M3</strong></td><td>iOS gyro permission requested via <code>DeviceOrientationEvent.requestPermission()</code> on first toggle tap (never on page load). If denied, GYRO sub-toggle auto-disables; AUDIO + HAPTIC remain available. (Native Capacitor app handles permission via <code>Info.plist</code> declaration; no in-app permission dance.)</td></tr><tr><td><strong>M4</strong></td><td><code>prefers-reduced-motion</code> users see only the AUDIO sub-toggle in the settings sheet. GYRO + HAPTIC are hidden (not &quot;disabled and visible&quot; — hidden, per ADR-022 spirit).</td></tr><tr><td><strong>M5</strong></td><td>Web Audio context is created <strong>lazily on first toggle tap</strong> (user gesture required). Suspended on <code>visibilitychange</code> to background; resumed on foreground. Per-route audio graph torn down + rebuilt on route change.</td></tr><tr><td><strong>M6</strong></td><td>Gyroscope mapping: reference-frame calibrated (G-C) — toggle on captures the current device orientation as &quot;home&quot;; subsequent rotations are deltas from home. Sensitivity <code>0.015 rad/deg</code>. Low-pass filter <code>smoothed = prev × 0.85 + raw × 0.15</code>. Dead zone ±2°.</td></tr><tr><td><strong>M7</strong></td><td>Touch-drag pauses gyro (T-B) — when the user is actively touching the canvas, gyro input is suppressed. 200 ms after touch-end, gyro resumes from the new position (no snap back to home).</td></tr><tr><td><strong>M8</strong></td><td>Haptics use <code>@capacitor/haptics</code> when running under Capacitor (PRD-015), <code>navigator.vibrate</code> on web. iOS web has no haptics — the HAPTIC sub-toggle is hidden when neither path is available. 12 distinct haptic patterns per RFC-020 §haptics.</td></tr><tr><td><strong>M9</strong></td><td>Sonification ducks to ~0.02 gain (≈ −34 dB) when PRD-016 audio narration is playing. Restored to 1.0 gain on narration end. Both toggles remain independent — neither force-disables the other.</td></tr><tr><td><strong>M10</strong></td><td>Sonification pauses entirely (gain → 0) when a screen reader is detected (<code>navigator.userAgent</code> heuristics + ARIA live region presence) — voice output and tonal output don&#39;t compete for the same channel.</td></tr><tr><td><strong>M11</strong></td><td>Per-route sonification graphs for all 11 routes (per RFC-020 §sonification). The 5 new route designs (<code>/science</code>, <code>/fleet</code>, <code>/iss</code>, <code>/tiangong</code>, <code>/mars</code>) reuse the agency tone palette + regime drone instrument from the original 6 routes — no entirely new instrument families.</td></tr><tr><td><strong>M12</strong></td><td>Bundle size budget: &lt; 15 KB minified gzipped for the entire sensory layer (audio.ts + haptics.ts + sensor.ts + sensory.ts). Web Audio API is native; only oscillator setup + gain graph code adds to bundle.</td></tr><tr><td><strong>M13</strong></td><td>Performance budget: no 60 fps drop on the lowest-tier supported device (mid-range Android per PRD-015). Sonification CPU &lt; 0.3 % steady-state.</td></tr><tr><td><strong>M14</strong></td><td>Capacitor build adds <strong>zero MB</strong> to the mobile bundle for the sensory layer itself (Web Audio + Capacitor Haptics are runtime APIs). The 15 KB JS lives in the existing app shell.</td></tr></tbody></table><hr><h2 id="§should-have-requirements" tabindex="-1">§should-have requirements <a class="header-anchor" href="#§should-have-requirements" aria-label="Permalink to &quot;§should-have requirements&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ID</th><th>Requirement</th></tr></thead><tbody><tr><td><strong>S1</strong></td><td>Recalibrate gesture: triple-tap on the screen recaptures gyro home orientation. Visual flash confirmation (~150 ms teal).</td></tr><tr><td><strong>S2</strong></td><td>First-time toggle-on shows a non-modal toast: &quot;Tilt to orbit · sound on · vibration on&quot;. Dismisses on next tap or after 4 s. Shown once per session.</td></tr><tr><td><strong>S3</strong></td><td>Sub-toggle state in the settings sheet animates between on/off (≤ 150 ms).</td></tr><tr><td><strong>S4</strong></td><td><code>/iss</code> and <code>/tiangong</code> selected-module tones get a short envelope on selection (attack ≤ 50 ms) so the change is perceived as an event, not a glitch.</td></tr><tr><td><strong>S5</strong></td><td>When AUDIO is on but no other modality, the master toggle icon shows a subtle pulse during active sonification (visual cue that audio is playing).</td></tr></tbody></table><hr><h2 id="§will-not-have-v1" tabindex="-1">§will-not-have (v1) <a class="header-anchor" href="#§will-not-have-v1" aria-label="Permalink to &quot;§will-not-have (v1)&quot;">​</a></h2><ul><li>Persistent settings across reloads (in-memory only per ADR-057; revisit in v1.x only if data justifies a single-cookie bitset).</li><li>iOS web haptics (no browser support; can&#39;t fix).</li><li>Tone.js or any external audio framework (Web Audio raw API only).</li><li><code>/fly</code> porkchop magnifier gyro control (conflicts with ADR-023).</li><li>User-adjustable sonification sensitivity / volume slider (v1.1).</li><li>Compass / planetarium-mode camera reference (v1.1).</li><li>MIDI output (v2).</li><li>Per-user listening profile / &quot;save my mix&quot; (out of scope; runtime-only).</li></ul><hr><h2 id="§success-criteria" tabindex="-1">§success-criteria <a class="header-anchor" href="#§success-criteria" aria-label="Permalink to &quot;§success-criteria&quot;">​</a></h2><p><strong>Editorial:</strong></p><ol><li>A first-time visitor toggles sensory on, walks through <code>/explore</code>, <code>/fly</code> (one mission arc), and <code>/moon</code>, and the audio difference between the three routes is <em>immediately perceptible</em> (verified by 3 reviewer listens before ship).</li><li>The Kepler chord on <code>/explore</code> lands as recognisable harmony (not noise) on the device&#39;s built-in speaker without headphones — verified on iPhone SE 3 + Pixel 5.</li></ol><p><strong>Technical:</strong> 3. v1 ship adds &lt; 15 KB minified gzipped to the bundle. 4. No 60 fps drop on a Pixel 5 / iPhone SE 3 with sensory enabled across all 11 routes. 5. Audio coexistence with PRD-016 narration verified: turning narration on while sonification plays drops sonification to ~0.02 gain within 50 ms; restored within 200 ms after narration ends. 6. iOS web gyro permission flow shows the system prompt only on toggle tap (not on page load); denial gracefully disables GYRO sub-toggle without affecting AUDIO/HAPTIC.</p><p><strong>Operational:</strong> 7. Manual test matrix passes on: iPhone SE 3 (iOS Safari), iPhone 14 Pro (Capacitor wrapper), Pixel 5 (Chrome), Pixel 5 (Capacitor wrapper), Galaxy A-series (Chrome), MacBook + Chrome (desktop AUDIO only), MacBook + Firefox (desktop AUDIO only).</p><hr><h2 id="§dependencies" tabindex="-1">§dependencies <a class="header-anchor" href="#§dependencies" aria-label="Permalink to &quot;§dependencies&quot;">​</a></h2><ul><li><strong>PRD-015 / RFC-018 (mobile wrapper) must ship first</strong> — the haptics integration uses <code>@capacitor/haptics</code> from the wrapper&#39;s plugin list.</li><li><strong>PRD-016 / RFC-019 (audio narration) must ship first</strong> — the sonification ducking rule (M9) requires the narration system to exist.</li><li><strong>ADR-057 (no localStorage)</strong> — constrains settings persistence to in-memory only.</li><li><strong>ADR-022 (reduced motion fallback path)</strong> — constrains the GYRO + HAPTIC visibility under reduced-motion preference.</li><li><strong>ADR-025 (accessibility — tier 1 claims)</strong> — constrains the screen-reader interaction (M10).</li><li><strong>ADR-018 (44 px touch targets)</strong> — constrains all sensory UI elements.</li><li><strong>ADR-023 (mobile magnifier)</strong> — blocks <code>/fly</code> porkchop gyro control.</li></ul><hr><h2 id="§resolved-decisions" tabindex="-1">§resolved decisions <a class="header-anchor" href="#§resolved-decisions" aria-label="Permalink to &quot;§resolved decisions&quot;">​</a></h2><p><em>Resolved 2026-05-16 in conversation with Marko.</em></p><ol><li><strong>Sonification scope — RESOLVED: All 11 routes</strong> (not just original 6 prototypes). Adds 5 new per-route sonification designs in RFC-020 §sonification: <code>/missions</code>, <code>/science</code>, <code>/fleet</code>, <code>/iss</code>, <code>/tiangong</code>, <code>/mars</code>.</li><li><strong>Capacitor haptics — RESOLVED: <code>@capacitor/haptics</code> in Capacitor builds, <code>navigator.vibrate</code> fallback on web.</strong> iOS gets basic Taptic Engine feedback when wrapped (not on iOS web).</li><li><strong>Audio narration coexistence — RESOLVED: Sonification ducks to ~0.02 gain while narration plays.</strong> Both toggles remain independent. Restored 200 ms after narration ends.</li><li><strong>Settings UI — RESOLVED: Two separate buttons in the nav</strong> (narration speaker icon + sensory waveform icon). Each has its own bottom-sheet. One icon = one capability.</li><li><strong>Storage — RESOLVED: in-memory only.</strong> ADR-057 forbids localStorage; the original RFC&#39;s &quot;v0.4 reconsider localStorage&quot; line is deleted entirely. Reload resets the master toggle to OFF.</li><li><strong>Gyro mapping (G-C), gyro+touch (T-B), per-screen sonification (S-C), haptics+audio interaction (I-B), toggle UX (U-2), iOS permission timing (P-A) — RESOLVED: all 6 original RFC choices stand.</strong> Mature design; no rework needed.</li></ol><hr><p><em>Additional decisions resolved 2026-05-16 (second batch):</em></p><ol start="7"><li><strong>Default master-toggle state — RESOLVED: Default OFF, with a one-time landing-page hint</strong> (&quot;tilt + sound + buzz — try sensory mode&quot;) dismissable toast on <code>/</code>. Opt-in is more polite + avoids the &quot;what&#39;s making noise&quot; reaction on shared / public devices.</li><li><strong><code>prefers-reduced-motion</code> × AUDIO — RESOLVED: AUDIO remains user-controllable</strong> under reduced-motion. Only GYRO + HAPTIC are hidden. Reduced-motion is a motion preference, not an audio preference.</li><li><strong>Recalibrate gesture — RESOLVED: Triple-tap on canvas.</strong> Discoverable via help text in settings sheet. 150 ms teal flash confirms.</li></ol><h2 id="§remaining-follow-ups" tabindex="-1">§remaining follow-ups <a class="header-anchor" href="#§remaining-follow-ups" aria-label="Permalink to &quot;§remaining follow-ups&quot;">​</a></h2><ol start="10"><li><strong>Sonification authoring review for the 5 new routes.</strong> RFC-020 §3.3 proposes designs based on each route&#39;s character; need a listening-test pass on each before ship. Marko + 1 reviewer per design = 5 listening sessions. Operational, not architectural.</li><li><strong>iPhone SE 3 audio quality test.</strong> The Kepler chord on built-in speakers (not headphones) at the SE&#39;s small driver — does it sound musical or muddy? Test before ship; tune oscillator gains down if muddy. Operational.</li><li><strong>Triple-tap × iOS accessibility shortcut conflict.</strong> iOS allows triple-tap to be bound to system accessibility features. If a real user collision surfaces during testing, switch the recalibrate gesture to a dedicated settings-sheet button. Implementation-time decision.</li></ol><hr><p><em>PRD-017 · Orrery · Sensory Layer · Drafted 2026-05-16 · Closes-into-RFC-020</em></p>',59)])])}const g=t(r,[["render",a]]);export{u as __pageData,g as default};
